use std::collections::VecDeque;

struct CircularBuffer {
    data: VecDeque<u8>,
}

impl CircularBuffer {
    fn new() -> Self {
        CircularBuffer { data: VecDeque::new() }
    }

    fn write_byte(&mut self, byte: u8) {
        self.data.push_back(byte);
    }

    fn read_backward_to_boundary(&self, start_index: usize, end_boundary: Option<usize>) -> Vec<u8> {
        let mut result = Vec::new();
        let data_len = self.data.len();
        let effective_end = match end_boundary {
            Some(e) if e < data_len => e,
            _ => 0
        };

        let actual_start = std::cmp::min(start_index, data_len - 1);

        if actual_start > data_len - 1 || effective_end >= data_len {
            return Vec::new();
        }

        let mut current_idx = actual_start;
        while let Some(element) = self.data.iter().nth(current_idx)
        {
            result.push(*element);
            if current_idx == effective_end {
                break;
            }
            if current_idx == 0 { break; }
            current_idx -= 1;
        }

        // Note: This simplified example uses VecDeque's indexing which is costly, 
        // but demonstrates the concept of iterating backward across a conceptual boundary.
        result.reverse(); // Since we iterated conceptually from high index to low index, reverse for correct order if needed elsewhere.
        result
    }
}

fn main() {
    let mut buffer = CircularBuffer::new();
    buffer.write_byte(0xAA);
    buffer.write_byte(0xBB);
    buffer.write_byte(0xCC); // CC is the 'latest' write
    buffer.write_byte(0xDD);

    // Simulate reading from index 3 (DD) backwards to before index 1 (stop at BB)
    let start = 3;
    let boundary_exclusive = Some(1); 

    let data = buffer.read_backward_to_boundary(start, boundary_exclusive);

    println!("Read Data: {:?}", data);
}

use std::collections::VecDeque;

struct FeatureStore {
    data: VecDeque<String>,
}

impl FeatureStore {
    fn new(initial_data: Vec<String>) -> Self {
        FeatureStore {
            data: initial_data.into()
        }
    }

    fn process_ends(&mut self) -> Option<(String, String)> {
        if self.data.len() < 2 {
            return None;
        }

        let oldest = self.data.pop_front().unwrap();
        let newest = self.data.pop_back().unwrap();
        Some((oldest, newest))
    }

    fn process_middle(&mut self) -> Option<String> {
        if self.data.is_empty() {
            return None;
        }
        let middle = self.data.pop_front().unwrap();
        Some(middle)
    }
}

fn main() {
    let mut store = FeatureStore::new(vec!["Record A".to_string(), "Record B".to_string(), "Record C".to_string(), "Record D".to_string()]);

    match store.process_ends() {
        Some((old, new)) => println!("Processed ends: Oldest={:?}, Newest={:?}", old, new),
        None => println!("Not enough data to process ends.")
    }

    match store.process_ends() {
        Some((old, new)) => println!("Processed ends: Oldest={:?}, Newest={:?}", old, new),
        None => println!("Not enough data to process ends.")
    }

    match store.process_middle() {
        Some(record) => println!("Processed middle record: {}", record),
        None => println!("No records left in the middle.")
    }
}

use std::collections::VecDeque;

fn main() {
    let mut keys: VecDeque<u32> = VecDeque::new();
    keys.push_back(100);
    keys.push_back(200);
    keys.push_back(300);

    println!("Processing from start to end:");
    for key in keys.iter() {
        println!("Key: {}", key);
    }

    println!("nProcessing from end to start (using DoubleEndedIterator capability): ");
    let mut count = 0;
    while let Some(key) = keys.pop_back() {
        println!("Key: {}", key);
        count += 1;
    }

    // Re-populate for a full demonstration if needed, but focusing on the core concept:
    let mut keys_for_reverse: VecDeque<u32> = VecDeque::new();
    keys_for_reverse.push_back(5);
    keys_for_reverse.push_back(15);
    keys_for_reverse.push_back(25);

    println!("nDemonstrating efficient reverse iteration on a structure that supports it:");
    for key in keys_for_reverse.iter().rev() {
        println!("Reverse Key: {}", key);
    }
}

use std::collections::VecDeque;

struct Job {
    id: u32,
    name: String,
    data: Vec<u8>,
}

impl std::fmt::Display for Job {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Job {}: {}", self.id, self.name)
    }
}

fn main() {
    let mut queue: VecDeque<Job> = VecDeque::new();
    queue.push_back(Job { id: 1, name: String::from("Compile") , data: vec![0xde]});
    queue.push_back(Job { id: 2, name: String::from("Test") , data: vec![0xad]});
    queue.push_back(Job { id: 3, name: String::from("Package") , data: vec![0xbe]});

    println!("--- Running Forward ---");
    for job in queue.iter() {
        println!("Executing: {}", job);
    }

    println!("n--- Cleaning Up (Reversed) ---");
    let reversed_jobs: Vec<Job> = queue.into_iter().collect();
    for job in reversed_jobs.into_iter() {
        println!("Cleanup Step: {}", job);
    }
}

use std::collections::VecDeque;

struct MessageQueue {
    queue: VecDeque<String>,
}

impl MessageQueue {
    fn new() -> Self {
        MessageQueue { queue: VecDeque::new() }
    }

    fn add_message(&mut self, message: String) {
        self.queue.push_back(message);
    }

    fn peek_start(&self) -> Option<&String> {
        self.queue.front()
    }

    fn pop_end(&mut self) -> Option<String> {
        self.queue.pop_back()
    }

    fn process_all(&self) {
        let mut current = self.queue.iter().collect::<Vec<_>>();
        println!("Processing all messages:");
        for item in current.iter() {
            println!("tFound: {}", item);
        }
    }
}

fn main() {
    let mut queue = MessageQueue::new();
    queue.add_message("Encrypted handshake start".to_string());
    queue.add_message("Key exchange data block 1".to_string());
    queue.add_message("Session established: OK".to_string());

    println!("--- Initial State ---");
    queue.process_all();

    if let Some(start) = queue.peek_start() {
        println!("nFirst thing I see at the start: {}", start);
    }

    let mut processed_count = 0;
    while let Some(msg) = queue.pop_end() {
        println!("tProcessed from end: {}", msg);
        processed_count += 1;
    }

    println!("Total messages popped from the end: {}", processed_count);
}
